{
  "mode": "method",
  "tests": [
    {
      "name": "valid_login_response",
      "input": {
        "username": "validUser",
        "password": "validPassword"
      },
      "output": {
        "status": "success",
        "roles": ["user", "admin"]
      },
      "notes": "Tests a valid login scenario to ensure the response includes the correct roles."
    },
    {
      "name": "invalid_login_response",
      "input": {
        "username": "invalidUser",
        "password": "invalidPassword"
      },
      "output": {
        "status": "error",
        "message": "Invalid username or password."
      },
      "notes": "Tests an invalid login scenario to ensure the error response is correct."
    },
    {
      "name": "missing_username",
      "input": {
        "username": "",
        "password": "somePassword"
      },
      "output": {
        "status": "error",
        "message": "Username is required."
      },
      "notes": "Tests the edge case of missing username to ensure proper validation."
    },
    {
      "name": "missing_password",
      "input": {
        "username": "someUser",
        "password": ""
      },
      "output": {
        "status": "error",
        "message": "Password is required."
      },
      "notes": "Tests the edge case of missing password to ensure proper validation."
    },
    {
      "name": "role_lookup_valid_user",
      "input": {
        "userId": 1
      },
      "output": {
        "roles": ["user", "admin"]
      },
      "notes": "Tests role lookup for a valid user ID to ensure correct roles are returned."
    },
    {
      "name": "role_lookup_invalid_user",
      "input": {
        "userId": 9999
      },
      "output": {
        "status": "error",
        "message": "User not found."
      },
      "notes": "Tests role lookup for an invalid user ID to ensure proper error handling."
    },
    {
      "name": "login_with_special_characters",
      "input": {
        "username": "user@123",
        "password": "pass!@#"
      },
      "output": {
        "status": "success",
        "roles": ["user"]
      },
      "notes": "Tests login with special characters in username and password to ensure they are handled correctly."
    },
    {
      "name": "role_lookup_no_roles",
      "input": {
        "userId": 2
      },
      "output": {
        "roles": []
      },
      "notes": "Tests role lookup for a user with no roles to ensure an empty array is returned."
    }
  ],
  "assumptions": "All user IDs and credentials used in tests are pre-defined in the database.",
  "notes": "Ensure that the database is seeded with necessary test data before running tests."
}
